import React, { useState, useEffect, useMemo } from 'react';
import { Language, CartItem } from './types';
import { PRODUCTS, TRANSLATIONS, WHATSAPP_NUMBER, INSTAGRAM_URL, FAQS, MOCK_REVIEWS } from './constants';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('ar');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [customer, setCustomer] = useState({ name: '', phone: '', location: '' });
  const [aiMessage, setAiMessage] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiThinking, setIsAiThinking] = useState(false);

  const [showReviews, setShowReviews] = useState(false);
  const [localReviews, setLocalReviews] = useState<any[]>([]);
  const [addedNotify, setAddedNotify] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const t = useMemo(() => TRANSLATIONS[lang], [lang]);

  useEffect(() => {
    const saved = localStorage.getItem('honey_house_reviews');
    if (saved) {
      try { setLocalReviews(JSON.parse(saved)); } catch (e) {}
    }
    if (cart.length === 0) {
      setCart([{ id: 'init-1', productId: PRODUCTS[0].id, priceId: PRODUCTS[0].prices[0].id, quantity: 1 }]);
    }
  }, []);

  useEffect(() => {
    document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const toggleLanguage = () => setLang(prev => (prev === 'ar' ? 'en' : 'ar'));

  const addToBasket = (productId: string, priceId: string) => {
    const newItem: CartItem = {
      id: Math.random().toString(36).substr(2, 9),
      productId,
      priceId,
      quantity: 1
    };
    if (cart.length === 1 && cart[0].id === 'init-1' && cart[0].quantity === 1 && cart[0].productId === PRODUCTS[0].id) {
       setCart([newItem]);
    } else {
       setCart([...cart, newItem]);
    }
    const prod = PRODUCTS.find(p => p.id === productId);
    setAddedNotify(lang === 'ar' ? `تمت إضافة ${prod?.titleAr} للسلة` : `Added ${prod?.titleEn} to basket`);
    setTimeout(() => setAddedNotify(null), 3000);
  };

  const removeProductLine = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateCartItem = (id: string, field: keyof CartItem, value: any) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        if (field === 'productId') {
          const product = PRODUCTS.find(p => p.id === value);
          updated.priceId = product ? product.prices[0].id : '';
        }
        return updated;
      }
      return item;
    }));
  };

  const totalOrderPrice = useMemo(() => {
    return cart.reduce((acc, item) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      return acc + (priceObj ? priceObj.price * item.quantity : 0);
    }, 0);
  }, [cart]);

  const handleSendOrder = () => {
    if (!customer.name || !customer.phone || !customer.location || cart.length === 0) {
      alert(t.errorFields);
      return;
    }
    let summary = '';
    cart.forEach((item, index) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      if (product && priceObj) {
        summary += `${index + 1}. ${lang === 'ar' ? product.titleAr : product.titleEn} (${lang === 'ar' ? priceObj.sizeAr : priceObj.sizeEn}) x ${item.quantity}\n`;
      }
    });
    const msg = `${t.whatsappOrderHeader}\n\n${t.whatsappName} ${customer.name}\n${t.whatsappPhone} ${customer.phone}\n${t.whatsappLocation} ${customer.location}\n\n${summary}\n${t.whatsappTotal} ${totalOrderPrice} ${t.currency}`;
    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  const handleAiConsult = async (customMsg?: string) => {
    const messageToUse = customMsg || aiMessage;
    if (!messageToUse.trim()) return;
    setIsAiThinking(true);
    setAiResponse('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `You are the Honey Sommelier for 'Honey House'. User language: ${lang}. Current context: Premium Egyptian honey products. User question: ${messageToUse}. Provide a very short, professional, and helpful response.`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      setAiResponse(response.text || '');
    } catch (e) { setAiResponse('Error connecting to AI.'); } finally { setIsAiThinking(false); }
  };

  const scrollToSection = (id: string) => {
    setIsMenuOpen(false);
    if (id === 'reviews-section') setShowReviews(true);
    setTimeout(() => {
      const el = document.getElementById(id);
      if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const allReviews = useMemo(() => {
    const local = localReviews.map(r => ({ ar: { name: r.name, comment: r.comment }, en: { name: r.name, comment: r.comment }, rating: r.rating }));
    return [...local, ...MOCK_REVIEWS];
  }, [localReviews]);

  return (
    <div className="min-h-screen text-slate-900 bg-[#FEFBF6] selection:bg-amber-200 antialiased font-primary">
      {/* Added Notification Toast */}
      {addedNotify && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-amber-600 text-white px-8 py-4 rounded-full font-black shadow-2xl animate-in fade-in slide-in-from-top-4 duration-300 flex items-center gap-3">
          <span className="text-xl">✅</span> {addedNotify}
        </div>
      )}

      {/* Ticker */}
      <div className="bg-amber-500 text-white py-2 text-xs md:text-sm font-bold border-b border-amber-600 relative z-[60] overflow-hidden">
         <div className="animate-marquee flex gap-12 whitespace-nowrap">
            <span>{t.tickerMsg1}</span><span>{t.tickerMsg2}</span><span>{t.tickerMsg3}</span>
            <span>{t.tickerMsg1}</span><span>{t.tickerMsg2}</span><span>{t.tickerMsg3}</span>
         </div>
      </div>

      {/* Navigation Bar */}
      <header className="sticky top-0 z-50 bg-white/90 backdrop-blur-2xl border-b border-amber-100 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 py-3 flex justify-between items-center">
          {/* Logo */}
          <button onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })} className="flex items-center gap-3 hover:opacity-80 transition-opacity">
             <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center p-1 shadow-lg overflow-hidden">
               <img src="https://imgur.com/doKxqHM.jpeg" alt="Logo" className="w-full h-full object-cover rounded-lg scale-125" />
             </div>
             <span className="text-xl font-black text-amber-900 hidden sm:inline-block">{t.companyName}</span>
          </button>

          {/* Desktop Navigation */}
          <nav className="hidden xl:flex items-center gap-1">
            <NavBtn icon="🍯" label={t.navSelections} onClick={() => scrollToSection('products-grid')} />
            <NavBtn icon="✨" label={t.navAi} onClick={() => scrollToSection('ai-assistant')} />
            <NavBtn icon="⭐" label={t.navReviews} onClick={() => scrollToSection('reviews-section')} />
            <NavBtn icon="📦" label={t.navOrder} onClick={() => scrollToSection('order-form')} highlight />
            <NavBtn icon="❓" label={t.navFaq} onClick={() => scrollToSection('faq-section')} />
            <NavBtn icon="📞" label={t.navContact} onClick={() => scrollToSection('footer-section')} />
          </nav>

          <div className="flex items-center gap-2">
             <button onClick={toggleLanguage} className="bg-amber-50 text-amber-900 py-2 px-4 rounded-xl text-xs font-black border border-amber-100 hover:bg-amber-100 transition-colors uppercase">
               {lang === 'ar' ? 'English' : 'العربية'}
             </button>

             {/* Mobile Menu Toggle */}
             <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="xl:hidden p-2 text-amber-900 bg-amber-50 rounded-xl border border-amber-100">
               {isMenuOpen ? (
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
               ) : (
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
               )}
             </button>
          </div>
        </div>

        {/* Mobile Menu Overlay */}
        <div className={`xl:hidden absolute top-full left-0 right-0 bg-white border-b border-amber-100 shadow-xl transition-all duration-300 origin-top ${isMenuOpen ? 'scale-y-100 opacity-100' : 'scale-y-0 opacity-0 pointer-events-none'}`}>
           <div className="p-6 flex flex-col gap-2">
              <MobileNavBtn icon="🍯" label={t.navSelections} onClick={() => scrollToSection('products-grid')} />
              <MobileNavBtn icon="✨" label={t.navAi} onClick={() => scrollToSection('ai-assistant')} />
              <MobileNavBtn icon="⭐" label={t.navReviews} onClick={() => scrollToSection('reviews-section')} />
              <MobileNavBtn icon="📦" label={t.navOrder} onClick={() => scrollToSection('order-form')} highlight />
              <MobileNavBtn icon="❓" label={t.navFaq} onClick={() => scrollToSection('faq-section')} />
              <MobileNavBtn icon="📞" label={t.navContact} onClick={() => scrollToSection('footer-section')} />
           </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-6 mt-12">
        {/* Hero Compact */}
        <section className="text-center mb-16 relative">
          <h1 className="text-5xl md:text-8xl font-black text-amber-950 mb-4 tracking-tighter leading-none">{t.companyName}</h1>
          <p className="text-xl md:text-2xl text-amber-800/70 font-medium italic mb-10 max-w-2xl mx-auto leading-relaxed">"{t.slogan}"</p>
          <div className="flex flex-col sm:flex-row justify-center gap-4">
             <button onClick={() => scrollToSection('products-grid')} className="bg-amber-500 text-white px-10 py-5 rounded-[2rem] font-black text-xl shadow-xl hover:bg-amber-600 hover:scale-105 transition-all flex items-center justify-center gap-3">
               <span>{t.orderNow}</span>
               <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg>
             </button>
             <div className="bg-white border border-amber-100 px-8 py-5 rounded-[2rem] font-bold text-amber-800 flex items-center justify-center gap-2 shadow-sm">
               <span className="text-xl">📍</span> {t.deliveryNote}
             </div>
          </div>
        </section>

        {/* Products Grid */}
        <section id="products-grid" className="mb-24 scroll-mt-32">
          <div className="flex flex-col md:flex-row justify-between items-end mb-12 gap-4">
            <div className="space-y-1">
              <span className="text-amber-600 font-black uppercase tracking-[0.3em] text-[10px]">{lang === 'ar' ? 'الجودة الملكية' : 'Royal Quality'}</span>
              <h2 className="text-4xl font-black text-amber-950">{lang === 'ar' ? 'منتجاتنا المختارة' : 'Our Luxury Selections'}</h2>
            </div>
            <p className="text-amber-700/60 font-medium text-sm border-b border-amber-200 pb-1">{lang === 'ar' ? 'اختر و أضف للسلة مباشرة' : 'Choose & add directly to basket'}</p>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
            {PRODUCTS.map(p => (
              <QuickProductCard 
                key={p.id} 
                product={p} 
                lang={lang} 
                currency={t.currency} 
                onAdd={addToBasket}
              />
            ))}
          </div>
        </section>

        {/* AI Assistant Section */}
        <section id="ai-assistant" className="scroll-mt-32 mb-24">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
             {/* AI Sommelier Card */}
             <div className="lg:col-span-2 bg-amber-950 text-amber-50 p-10 md:p-14 rounded-[3.5rem] shadow-2xl relative overflow-hidden group">
                <div className="relative z-10">
                  <div className="flex items-center gap-3 mb-6">
                    <div className="w-12 h-12 bg-amber-500 rounded-2xl flex items-center justify-center text-2xl shadow-lg">✨</div>
                    <h3 className="text-3xl font-black">{t.aiAssistantTitle}</h3>
                  </div>
                  <p className="opacity-70 text-lg mb-10 max-w-xl leading-relaxed">{t.aiAssistantDesc}</p>

                  <div className="flex flex-col sm:flex-row gap-3 bg-white/10 p-3 rounded-3xl backdrop-blur-xl border border-white/10 shadow-inner">
                     <input 
                      type="text" value={aiMessage} onChange={e => setAiMessage(e.target.value)}
                      placeholder={t.aiPlaceholder} className="flex-grow bg-transparent px-5 py-4 outline-none text-white placeholder:text-white/30 text-lg"
                      onKeyPress={(e) => e.key === 'Enter' && handleAiConsult()}
                     />
                     <button onClick={() => handleAiConsult()} disabled={isAiThinking} className="bg-amber-500 text-amber-950 px-8 py-4 rounded-2xl font-black hover:bg-white transition-all disabled:opacity-50">
                       {isAiThinking ? (
                         <div className="flex items-center gap-2">
                            <div className="w-2 h-2 bg-amber-950 rounded-full animate-bounce"></div>
                            <div className="w-2 h-2 bg-amber-950 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                            <div className="w-2 h-2 bg-amber-950 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                         </div>
                       ) : (lang === 'ar' ? 'استشر الخبير' : 'Consult Expert')}
                     </button>
                  </div>

                  {aiResponse && (
                    <div className="mt-8 p-6 bg-amber-500/10 rounded-3xl border border-amber-500/20 text-lg italic leading-relaxed animate-in fade-in slide-in-from-top-4 duration-500">
                      "{aiResponse}"
                    </div>
                  )}

                  <div className="mt-8 flex flex-wrap gap-2">
                    {[t.aiPrompt1, t.aiPrompt2, t.aiPrompt3].map((prompt, i) => (
                      <button key={i} onClick={() => { setAiMessage(prompt); handleAiConsult(prompt); }} className="text-xs bg-white/5 hover:bg-white/20 px-4 py-2 rounded-full transition-colors border border-white/10">
                        {prompt}
                      </button>
                    ))}
                  </div>
                </div>
                {/* Decorative BG element */}
                <div className="absolute -bottom-20 -right-20 w-80 h-80 bg-amber-500/10 rounded-full blur-3xl group-hover:bg-amber-500/20 transition-all duration-1000"></div>
             </div>

             {/* Stats & Trust */}
             <div className="grid grid-cols-2 gap-4">
                <MiniStat icon="⭐" val="4.9" label={lang === 'ar' ? 'تقييمنا' : 'Rating'} onClick={() => scrollToSection('reviews-section')} />
                <MiniStat icon="🚛" val="24h" label={lang === 'ar' ? 'توصيل' : 'Delivery'} />
                <MiniStat icon="💎" val="100%" label={lang === 'ar' ? 'طبيعي' : 'Natural'} />
                <MiniStat icon="✅" val="CERT" label={lang === 'ar' ? 'مضمون' : 'Certified'} />
             </div>
          </div>
        </section>

        {/* Order Form Section */}
        <section id="order-form" className="bg-white p-10 md:p-20 rounded-[4rem] shadow-2xl border border-amber-100/50 max-w-5xl mx-auto mb-24 relative scroll-mt-32">
          <div className="text-center mb-16">
            <span className="text-amber-500 font-black uppercase tracking-[0.4em] text-xs mb-4 block">Order Details</span>
            <h2 className="text-5xl font-black text-amber-950 mb-4">{t.orderNow}</h2>
            <p className="text-amber-700/60 max-w-md mx-auto text-lg">{t.fillForm}</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 mb-10">
            <InputGroup label={t.nameLabel} placeholder={t.namePlaceholder} value={customer.name} onChange={v => setCustomer({...customer, name: v})} />
            <InputGroup label={t.phoneLabel} placeholder={t.phonePlaceholder} value={customer.phone} onChange={v => setCustomer({...customer, phone: v})} />
          </div>
          <InputGroup label={t.locationLabel} placeholder={t.locationPlaceholder} value={customer.location} onChange={v => setCustomer({...customer, location: v})} />

          <div className="mt-16 bg-slate-50 p-8 md:p-12 rounded-[3.5rem] border border-slate-100 space-y-6">
            <div className="flex justify-between items-center mb-6">
               <h4 className="font-black text-amber-900 uppercase tracking-widest text-sm">{lang === 'ar' ? 'سلة المشتريات' : 'Shopping Basket'}</h4>
               <span className="bg-amber-100 text-amber-800 px-3 py-1 rounded-full text-xs font-bold">{cart.length} {lang === 'ar' ? 'منتجات' : 'Items'}</span>
            </div>
            {cart.length === 0 ? (
              <p className="text-center py-16 opacity-30 italic text-xl">{lang === 'ar' ? 'السلة فارغة حالياً' : 'Your basket is currently empty'}</p>
            ) : (
              <div className="space-y-4">
                {cart.map(item => <CartRow key={item.id} item={item} lang={lang} onUpdate={updateCartItem} onRemove={() => removeProductLine(item.id)} isOnly={cart.length === 1} t={t} />)}
              </div>
            )}
            <button onClick={() => scrollToSection('products-grid')} className="w-full py-5 rounded-2xl border-2 border-dashed border-amber-300 text-amber-800 font-black hover:bg-amber-100 transition-all text-sm flex items-center justify-center gap-2">
              <span className="text-xl">+</span> {t.addProduct}
            </button>
          </div>

          <div className="mt-16 flex flex-col items-center">
             <div className="text-6xl font-black text-amber-600 mb-12 flex items-baseline gap-3">
               <span className="text-base opacity-40 uppercase tracking-widest font-bold">{t.total}</span>
               {totalOrderPrice} 
               <span className="text-lg font-black">{t.currency}</span>
             </div>
             <button onClick={handleSendOrder} className="w-full max-w-xl bg-amber-500 text-white font-black py-7 rounded-[2.5rem] text-2xl shadow-2xl shadow-amber-500/30 hover:bg-amber-600 active:scale-95 transition-all flex items-center justify-center gap-4">
                <span className="text-3xl">📲</span> {t.sendOrder}
             </button>
          </div>
        </section>

        {/* Reviews Section */}
        <section id="reviews-section" className="mb-24 scroll-mt-32">
          <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-6">
             <div className="text-center md:text-start">
               <h2 className="text-4xl font-black text-amber-950">{t.reviewsTitle}</h2>
               <p className="text-amber-700/60 font-medium text-lg mt-2">{lang === 'ar' ? 'ماذا يقول عشاق العسل لدينا' : 'What our honey lovers are saying'}</p>
             </div>
             <button onClick={() => window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(t.whatsappReviewTemplate)}`)} className="bg-amber-950 text-white px-8 py-4 rounded-2xl font-black hover:bg-amber-800 transition-colors flex items-center gap-2">
               <span>{t.leaveReview}</span>
               <span className="text-xl">✨</span>
             </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
             {allReviews.map((r, i) => (
               <div key={i} className="bg-white p-10 rounded-[3rem] border border-amber-50 shadow-sm relative group hover:shadow-xl hover:-translate-y-1 transition-all">
                  <div className="flex items-center gap-1 mb-6">
                    {[...Array(r.rating)].map((_, i) => <span key={i} className="text-amber-400 text-xl">★</span>)}
                  </div>
                  <p className="text-amber-950/80 italic text-lg mb-8 leading-relaxed">"{lang === 'ar' ? r.ar.comment : r.en.comment}"</p>
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-amber-100 rounded-full flex items-center justify-center text-xl font-black text-amber-600">
                      {r.en.name.charAt(0)}
                    </div>
                    <div>
                      <p className="font-black text-amber-950">{lang === 'ar' ? r.ar.name : r.en.name}</p>
                      <p className="text-[10px] text-amber-500 font-bold uppercase tracking-widest">{lang === 'ar' ? 'عميل موثق' : 'Verified Customer'}</p>
                    </div>
                  </div>
               </div>
             ))}
          </div>
        </section>

        {/* FAQ Section */}
        <section id="faq-section" className="mb-24 scroll-mt-32">
           <div className="max-w-4xl mx-auto">
             <div className="text-center mb-12">
               <h2 className="text-4xl font-black text-amber-950 mb-4">{t.faqTitle}</h2>
               <p className="text-amber-700/60">{lang === 'ar' ? 'كل ما تحتاج لمعرفته عن منتجاتنا' : 'Everything you need to know about our honey'}</p>
             </div>
             <div className="space-y-4">
               {FAQS.map((f, i) => <FaqMini key={i} q={lang === 'ar' ? f.ar.q : f.en.q} a={lang === 'ar' ? f.ar.a : f.en.a} />)}
             </div>
           </div>
        </section>

        {/* Footer/Contact Section */}
        <footer id="footer-section" className="mb-24 scroll-mt-32">
           <div className="bg-amber-100/30 p-12 md:p-20 rounded-[4rem] border border-amber-100/50 flex flex-col md:flex-row justify-between items-center gap-16 text-center md:text-start">
              <div className="max-w-md">
                <h2 className="text-3xl font-black text-amber-950 mb-6">{t.whyChooseUs}</h2>
                <div className="grid grid-cols-2 gap-6">
                  <div className="flex flex-col gap-2">
                    <span className="text-3xl">🌿</span>
                    <span className="text-sm font-black text-amber-900/60 uppercase tracking-widest">{t.natural}</span>
                  </div>
                  <div className="flex flex-col gap-2">
                    <span className="text-3xl">🛡️</span>
                    <span className="text-sm font-black text-amber-900/60 uppercase tracking-widest">{t.labTested}</span>
                  </div>
                  <div className="flex flex-col gap-2">
                    <span className="text-3xl">🏘️</span>
                    <span className="text-sm font-black text-amber-900/60 uppercase tracking-widest">{t.direct}</span>
                  </div>
                  <div className="flex flex-col gap-2">
                    <span className="text-3xl">🚀</span>
                    <span className="text-sm font-black text-amber-900/60 uppercase tracking-widest">{t.fastDelivery}</span>
                  </div>
                </div>
              </div>

              <div className="flex flex-col items-center md:items-end gap-8">
                 <div className="flex items-center gap-4">
                    <div className="text-right hidden sm:block">
                      <p className="text-xs font-black text-amber-900/40 uppercase tracking-widest mb-1">{t.navContact}</p>
                      <p className="text-xl font-black text-amber-950">+971 56 832 6116</p>
                    </div>
                    <div className="w-16 h-16 bg-amber-500 rounded-3xl flex items-center justify-center text-3xl shadow-xl">🍯</div>
                 </div>
                 <div className="flex gap-4">
                    <a href={INSTAGRAM_URL} target="_blank" rel="noopener noreferrer" className="w-16 h-16 bg-white text-amber-950 rounded-[1.5rem] flex flex-col items-center justify-center font-black shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all border border-amber-100">
                      <span className="text-sm">IG</span>
                    </a>
