    <span className="whitespace-nowrap uppercase tracking-tighter">{label}</span>
  </button>
);

const HtmlStyleProductCard = ({ product, lang, currency, onAdd, t }: any) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const currentPrice = product.prices[sizeIdx];

  return (
    <div className="bg-white rounded-[2.5rem] shadow-xl overflow-hidden flex flex-col transition-all duration-500 hover:shadow-2xl hover:-translate-y-1 border border-amber-50/50 group">
        <div className="h-[320px] flex items-center justify-center p-8 bg-white overflow-hidden relative">
             <img src={product.image} alt={product.titleEn} className="max-w-full max-h-full object-contain transition-transform duration-700 group-hover:scale-110" />
        </div>
        <div className="p-10 flex-grow flex flex-col">
            <h3 className="text-3xl font-bold text-[#6B4226] mb-3 leading-tight">
              {lang === 'ar' ? product.titleAr : product.titleEn}
            </h3>
            <p className="text-[#A16207] mb-8 flex-grow text-lg leading-relaxed opacity-80">
              {lang === 'ar' ? product.descriptionAr : product.descriptionEn}
            </p>

            <div className="mb-8">
                <p className="text-sm font-black text-[#6B4226]/40 uppercase tracking-widest mb-4">{t.chooseSize}</p>
                <div className="flex flex-wrap gap-2">
                    {product.prices.map((p: any, i: number) => (
                      <button 
                        key={p.id}
                        onClick={() => setSizeIdx(i)} 
                        className={`border-2 rounded-full px-6 py-2.5 text-sm font-black transition-all ${sizeIdx === i ? 'bg-[#6B4226] text-white border-[#6B4226] shadow-lg scale-105' : 'border-slate-100 text-slate-400 hover:border-amber-200'}`}
