                <button 
                  onClick={() => onAdd(product.id, currentPrice.id)}
                  className="w-full bg-[#FBBF24] hover:bg-[#F59E0B] text-amber-950 font-black py-5 px-8 rounded-3xl shadow-xl transform active:scale-95 transition-all text-xl flex items-center justify-center gap-4"
