const FaqMini = ({ q, a }: any) => {
  const [open, setOpen] = useState(false);
  return (
    <div className="bg-white rounded-[2.5rem] border border-amber-50 overflow-hidden shadow-sm hover:shadow-md transition-shadow">
       <button onClick={() => setOpen(!open)} className="w-full p-8 text-start font-black text-amber-950 text-xl flex justify-between items-center group">
          <span className="leading-tight">{q}</span>
          <span className={`w-10 h-10 rounded-2xl bg-amber-50 flex items-center justify-center transition-all duration-500 ${open ? 'rotate-180 bg-amber-500 text-white' : 'text-amber-500'}`}>
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M19 9l-7 7-7-7" /></svg>
          </span>
       </button>
       <div className={`transition-all duration-500 ease-in-out overflow-hidden ${open ? 'max-h-[500px] opacity-100' : 'max-h-0 opacity-0'}`}>
          <div className="px-8 pb-8 text-lg text-amber-800/60 leading-relaxed border-t border-amber-50 pt-8">{a}</div>
       </div>
    </div>
  );
};

const InputGroup = ({ label, placeholder, value, onChange }: any) => (
  <div className="space-y-4">
    <label className="text-[10px] font-black text-amber-900/30 uppercase tracking-[0.3em] px-2">{label}</label>
    <input 
      type="text" required value={value} onChange={e => onChange(e.target.value)}
      className="w-full p-6 bg-slate-50 rounded-3xl border border-slate-100 focus:ring-8 focus:ring-amber-500/5 focus:border-amber-500 outline-none transition-all placeholder:text-slate-300 font-bold text-lg"
      placeholder={placeholder}
    />
  </div>
);

const FooterBadge = ({ icon, label }: any) => (
  <div className="flex flex-col gap-3">
    <span className="text-4xl">{icon}</span>
    <span className="text-xs font-black text-amber-900/60 uppercase tracking-widest">{label}</span>
  </div>
);

const CartRow = ({ item, lang, onUpdate, onRemove, isOnly, t }: any) => {
  const prod = PRODUCTS.find(p => p.id === item.productId);
  return (
    <div className="flex flex-col sm:flex-row items-center gap-6 bg-white p-6 rounded-[2.5rem] shadow-sm border border-amber-100/30 hover:shadow-md transition-shadow">
      <div className="w-20 h-20 bg-amber-50 rounded-3xl flex items-center justify-center p-3 shrink-0">
         <img src={prod?.image} alt="Cart item" className="w-full h-full object-contain" />
      </div>
      <div className="flex-grow text-center sm:text-start">
         <p className="font-black text-amber-950 text-xl mb-2">{lang === 'ar' ? prod?.titleAr : prod?.titleEn}</p>
         <select value={item.priceId} onChange={e => onUpdate(item.id, 'priceId', e.target.value)} className="bg-amber-50 px-4 py-2 rounded-xl text-[11px] font-black text-amber-700 outline-none border border-amber-100">
            {prod?.prices.map(pr => <option key={pr.id} value={pr.id}>{lang === 'ar' ? pr.sizeAr : pr.sizeEn} ({pr.price} {t.currency})</option>)}
         </select>
      </div>
      <div className="flex items-center bg-slate-100 rounded-2xl px-2 py-1 shrink-0 shadow-inner">
         <button onClick={() => onUpdate(item.id, 'quantity', Math.max(1, item.quantity - 1))} className="w-12 h-12 flex items-center justify-center text-amber-900 font-black text-2xl hover:text-amber-500 transition-colors">-</button>
         <span className="w-10 text-center font-black text-xl">{item.quantity}</span>
         <button onClick={() => onUpdate(item.id, 'quantity', item.quantity + 1)} className="w-12 h-12 flex items-center justify-center text-amber-900 font-black text-2xl hover:text-amber-500 transition-colors">+</button>
      </div>
      {!isOnly && (
        <button onClick={onRemove} className="text-red-400 p-4 hover:bg-red-50 rounded-2xl shrink-0 transition-all">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
        </button>
      )}
    </div>
  );
};

export default App;

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  base: '/home-honey-orders/',
  define: {
    'process.env.API_KEY': JSON.stringify(process.env.API_KEY)
  }
});

import React, { useState, useEffect, useMemo } from 'react';
import { Language, CartItem } from './types';
import { PRODUCTS, TRANSLATIONS, WHATSAPP_NUMBER, INSTAGRAM_URL, FAQS, MOCK_REVIEWS } from './constants';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('ar');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [customer, setCustomer] = useState({ name: '', phone: '', location: '' });
  const [aiMessage, setAiMessage] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiThinking, setIsAiThinking] = useState(false);

  const [localReviews, setLocalReviews] = useState<any[]>([]);
  const [showReviewForm, setShowReviewForm] = useState(false);
  const [newReview, setNewReview] = useState({ name: '', rating: 5, comment: '' });
  const [addedNotify, setAddedNotify] = useState<string | null>(null);

  const t = useMemo(() => TRANSLATIONS[lang], [lang]);

  useEffect(() => {
    const saved = localStorage.getItem('honey_house_reviews_v4');
    if (saved) {
      try { setLocalReviews(JSON.parse(saved)); } catch (e) {}
    }
    // Pre-fill one empty order line
    if (cart.length === 0) {
      setCart([{ id: 'init-1', productId: PRODUCTS[0].id, priceId: PRODUCTS[0].prices[0].id, quantity: 1 }]);
    }
  }, []);

  useEffect(() => {
    document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const toggleLanguage = () => setLang(prev => (prev === 'ar' ? 'en' : 'ar'));

  const addToBasket = (productId: string, priceId: string) => {
    const newItem: CartItem = {
      id: Math.random().toString(36).substr(2, 9),
      productId,
      priceId,
      quantity: 1
    };
    if (cart.length === 1 && cart[0].id === 'init-1') {
       setCart([newItem]);
    } else {
       setCart([...cart, newItem]);
    }
    const prod = PRODUCTS.find(p => p.id === productId);
    setAddedNotify(lang === 'ar' ? `تمت إضافة ${prod?.titleAr} للسلة` : `Added ${prod?.titleEn} to basket`);
    setTimeout(() => setAddedNotify(null), 3000);
  };

  const removeProductLine = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateCartItem = (id: string, field: keyof CartItem, value: any) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        if (field === 'productId') {
          const product = PRODUCTS.find(p => p.id === value);
          updated.priceId = product ? product.prices[0].id : '';
        }
        return updated;
      }
      return item;
    }));
  };

  const totalOrderPrice = useMemo(() => {
    return cart.reduce((acc, item) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      return acc + (priceObj ? priceObj.price * item.quantity : 0);
    }, 0);
  }, [cart]);

  const handleSendOrder = () => {
    if (!customer.name || !customer.phone || !customer.location || cart.length === 0) {
      alert(t.errorFields);
      return;
    }
    let summary = '';
    cart.forEach((item, index) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      if (product && priceObj) {
        summary += `${index + 1}. ${lang === 'ar' ? product.titleAr : product.titleEn} (${lang === 'ar' ? priceObj.sizeAr : priceObj.sizeEn}) x ${item.quantity}\n`;
      }
    });
    const msg = `${t.whatsappOrderHeader}\n\n${t.whatsappName} ${customer.name}\n${t.whatsappPhone} ${customer.phone}\n${t.whatsappLocation} ${customer.location}\n\n${summary}\n${t.whatsappTotal} ${totalOrderPrice} ${t.currency}`;
    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  const handleAiConsult = async (customMsg?: string) => {
    const messageToUse = customMsg || aiMessage;
    if (!messageToUse.trim()) return;
    setIsAiThinking(true);
    setAiResponse('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `You are the Honey Sommelier for 'Honey House'. Context: Premium Egyptian honey. Language: ${lang}. Answer very concisely. User asked: ${messageToUse}`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      setAiResponse(response.text || '');
    } catch (e) { setAiResponse('AI Error. Check API Key.'); } finally { setIsAiThinking(false); }
  };

  const submitReview = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newReview.name || !newReview.comment) return;
    const reviewObj = {
      ar: { name: newReview.name, comment: newReview.comment },
      en: { name: newReview.name, comment: newReview.comment },
      rating: newReview.rating
    };
    const updated = [reviewObj, ...localReviews];
    setLocalReviews(updated);
    localStorage.setItem('honey_house_reviews_v4', JSON.stringify(updated));
    setNewReview({ name: '', rating: 5, comment: '' });
    setShowReviewForm(false);
  };

  const scrollToSection = (id: string) => {
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  return (
    <div className="min-h-screen text-slate-900 bg-[#FEFBF6] selection:bg-amber-200 antialiased font-primary">
      {addedNotify && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-amber-600 text-white px-8 py-4 rounded-full font-black shadow-2xl animate-in fade-in slide-in-from-top-4 duration-300">
          ✅ {addedNotify}
        </div>
      )}

      {/* Ticker */}
      <div className="bg-amber-500 text-white py-2 text-xs md:text-sm font-bold border-b border-amber-600 relative z-[60] overflow-hidden">
         <div className="animate-marquee flex gap-12 whitespace-nowrap">
            <span>{t.tickerMsg1}</span><span>{t.tickerMsg2}</span><span>{t.tickerMsg3}</span>
            <span>{t.tickerMsg1}</span><span>{t.tickerMsg2}</span><span>{t.tickerMsg3}</span>
         </div>
      </div>

      {/* Navigation */}
      <header className="sticky top-0 z-50 bg-white/95 backdrop-blur-md border-b border-amber-100 shadow-sm px-4">
        <div className="max-w-7xl mx-auto py-3 flex items-center justify-between gap-4 overflow-x-auto no-scrollbar">
          <div className="flex items-center gap-3 shrink-0">
             <img src="https://imgur.com/doKxqHM.jpeg" alt="Logo" className="w-10 h-10 rounded-lg shadow-md" />
             <span className="text-xl font-black text-amber-950 whitespace-nowrap">{t.companyName}</span>
          </div>

          <nav className="flex items-center gap-2">
            <NavBtn label={t.navAi} onClick={() => scrollToSection('ai-assistant')} />
            <NavBtn label={t.navSelections} onClick={() => scrollToSection('products-grid')} />
            <NavBtn label={t.navReviews} onClick={() => scrollToSection('reviews-section')} />
            <NavBtn label={t.navOrder} onClick={() => scrollToSection('order-form')} highlight />
            <button onClick={toggleLanguage} className="bg-amber-50 text-amber-950 py-2 px-4 rounded-xl text-xs font-black border border-amber-100 uppercase ml-2">{lang === 'ar' ? 'EN' : 'AR'}</button>
          </nav>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-6 mt-12">
        {/* Hero */}
        <section className="text-center mb-16">
          <h1 className="text-5xl md:text-7xl font-black text-amber-950 mb-6 tracking-tight leading-none">{t.companyName}</h1>
          <p className="text-xl md:text-2xl text-amber-800/70 font-medium italic mb-8">"{t.slogan}"</p>
          <div className="bg-amber-100 border-r-4 border-amber-500 text-amber-800 p-6 rounded-2xl shadow-sm max-w-2xl mx-auto">
              <h2 className="text-2xl font-black">{t.grandOpening}</h2>
              <p className="text-lg font-bold mt-1">{t.limitedTime}</p>
          </div>
        </section>

        {/* AI Assistant (FIRST) */}
        <section id="ai-assistant" className="scroll-mt-32 mb-24">
          <div className="bg-amber-950 text-amber-50 p-10 md:p-14 rounded-[3rem] shadow-2xl relative overflow-hidden">
            <div className="relative z-10 flex flex-col md:flex-row gap-12 items-center">
              <div className="flex-1">
                <div className="flex items-center gap-3 mb-6">
                  <div className="w-12 h-12 bg-amber-500 rounded-2xl flex items-center justify-center text-2xl shadow-lg">✨</div>
                  <h3 className="text-3xl font-black">{t.aiAssistantTitle}</h3>
                </div>
                <p className="opacity-70 text-lg mb-10 max-w-xl leading-relaxed">{t.aiAssistantDesc}</p>
                <div className="flex flex-col sm:flex-row gap-3 bg-white/10 p-2 rounded-2xl border border-white/10 backdrop-blur-sm">
                   <input 
                    type="text" value={aiMessage} onChange={e => setAiMessage(e.target.value)}
                    placeholder={t.aiPlaceholder} className="flex-grow bg-transparent px-5 py-3 outline-none text-white text-lg"
                    onKeyPress={(e) => e.key === 'Enter' && handleAiConsult()}
                   />
                   <button onClick={() => handleAiConsult()} disabled={isAiThinking} className="bg-amber-500 text-amber-950 px-8 py-3 rounded-xl font-black hover:bg-white transition-all">
                     {isAiThinking ? t.aiThinking : (lang === 'ar' ? 'اسأل الخبير' : 'Ask AI')}
                   </button>
                </div>
                {aiResponse && <div className="mt-6 p-6 bg-white/5 rounded-2xl italic border border-white/5 animate-in fade-in duration-500">"{aiResponse}"</div>}
              </div>
              <div className="hidden lg:flex gap-4">
                <div className="bg-white/5 p-8 rounded-3xl text-center border border-white/5 backdrop-blur-md">
                   <div className="text-4xl mb-2">🌿</div>
                   <div className="font-black text-2xl">100%</div>
                   <div className="text-[10px] opacity-50 uppercase tracking-widest">{t.natural}</div>
                </div>
                <div className="bg-white/5 p-8 rounded-3xl text-center border border-white/5 backdrop-blur-md mt-10">
                   <div className="text-4xl mb-2">🛡️</div>
                   <div className="font-black text-2xl">LAB</div>
                   <div className="text-[10px] opacity-50 uppercase tracking-widest">{t.labTested}</div>
                </div>
              </div>
            </div>
            <div className="absolute -bottom-20 -right-20 w-80 h-80 bg-amber-500/10 rounded-full blur-3xl"></div>
          </div>
        </section>

        {/* Luxury Selections */}
        <section id="products-grid" className="mb-24 scroll-mt-32">
          <div className="text-center mb-16">
            <h2 className="text-5xl font-black text-amber-950 mb-4">{t.navSelections}</h2>
            <p className="text-amber-700/60 font-medium text-lg">{t.deliveryNote}</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
            {PRODUCTS.map(p => (
              <ProductCard key={p.id} product={p} lang={lang} currency={t.currency} onAdd={addToBasket} t={t} />
            ))}
          </div>
        </section>

        {/* Order Form */}
        <section id="order-form" className="bg-white p-10 md:p-20 rounded-[4rem] shadow-xl border border-amber-100/50 max-w-4xl mx-auto mb-24 scroll-mt-32">
          <h2 className="text-4xl font-black text-amber-950 mb-10 text-center">{t.orderNow}</h2>
          <div className="space-y-6 mb-10">
            <InputGroup label={t.nameLabel} placeholder={t.namePlaceholder} value={customer.name} onChange={v => setCustomer({...customer, name: v})} />
            <InputGroup label={t.phoneLabel} placeholder={t.phonePlaceholder} value={customer.phone} onChange={v => setCustomer({...customer, phone: v})} />
            <InputGroup label={t.locationLabel} placeholder={t.locationPlaceholder} value={customer.location} onChange={v => setCustomer({...customer, location: v})} />
          </div>

          <div className="bg-slate-50 p-8 rounded-3xl space-y-4">
            <h4 className="font-black text-amber-900 uppercase text-xs tracking-widest mb-4">{lang === 'ar' ? 'محتويات السلة' : 'Basket Summary'}</h4>
            {cart.map(item => <CartRow key={item.id} item={item} lang={lang} onUpdate={updateCartItem} onRemove={() => removeProductLine(item.id)} isOnly={cart.length === 1} t={t} />)}
            <button onClick={() => scrollToSection('products-grid')} className="w-full py-4 rounded-xl border-2 border-dashed border-amber-200 text-amber-800 font-bold hover:bg-amber-100 transition-all">+ {t.addProduct}</button>
          </div>

          <div className="mt-10 flex flex-col items-center">
             <div className="text-5xl font-black text-amber-600 mb-8">{totalOrderPrice} {t.currency}</div>
             <button onClick={handleSendOrder} className="w-full bg-amber-500 text-white font-black py-6 rounded-2xl text-xl shadow-lg hover:bg-amber-600 transition-all flex items-center justify-center gap-3">
                <span>📲</span> {t.sendOrder}
             </button>
          </div>
        </section>

        {/* Reviews */}
        <section id="reviews-section" className="mb-24 scroll-mt-32">
          <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-6">
             <div>
               <h2 className="text-4xl font-black text-amber-950">{t.reviewsTitle}</h2>
               <p className="text-amber-700/60 font-medium text-lg">{lang === 'ar' ? 'آراء حقيقية من عملائنا' : 'Real words from real customers'}</p>
             </div>
             <button onClick={() => setShowReviewForm(!showReviewForm)} className="bg-amber-950 text-white px-8 py-4 rounded-xl font-black hover:bg-amber-800 transition-colors">
               {t.leaveReview} ✨
             </button>
          </div>

          {showReviewForm && (
            <div className="max-w-xl mx-auto bg-white p-10 rounded-3xl shadow-xl mb-12 border border-amber-100 animate-in slide-in-from-top-4">
               <form onSubmit={submitReview} className="space-y-6">
                  <InputGroup label={t.nameLabel} placeholder={t.namePlaceholder} value={newReview.name} onChange={v => setNewReview({...newReview, name: v})} />
                  <div>
                    <label className="text-xs font-black text-amber-900/40 uppercase mb-2 block">{lang === 'ar' ? 'التقييم' : 'Rating'}</label>
                    <div className="flex gap-1">
                       {[1,2,3,4,5].map(s => (
                         <button type="button" key={s} onClick={() => setNewReview({...newReview, rating: s})} className={`text-3xl ${newReview.rating >= s ? 'text-amber-400' : 'text-slate-200'}`}>★</button>
                       ))}
                    </div>
                  </div>
                  <textarea value={newReview.comment} onChange={e => setNewReview({...newReview, comment: e.target.value})} className="w-full p-5 bg-slate-50 rounded-2xl border border-slate-100 font-bold outline-none h-32" placeholder={lang === 'ar' ? 'اكتب تجربتك هنا...' : 'Write your experience here...'} required />
                  <button type="submit" className="w-full bg-amber-500 text-white py-4 rounded-xl font-black">نشر التقييم | Submit Review</button>
               </form>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
             {[...localReviews, ...MOCK_REVIEWS].map((r, i) => (
               <div key={i} className="bg-white p-8 rounded-3xl border border-amber-50 shadow-sm hover:shadow-md transition-shadow">
                  <div className="flex text-amber-400 mb-4">{"★".repeat(r.rating)}</div>
                  <p className="text-amber-950/80 italic text-lg mb-6 leading-relaxed">"{lang === 'ar' ? r.ar.comment : r.en.comment}"</p>
                  <p className="font-black text-amber-950">{lang === 'ar' ? r.ar.name : r.en.name}</p>
               </div>
             ))}
          </div>
        </section>

        {/* Footer */}
        <footer className="mb-24 pt-12 border-t border-amber-100 text-center">
           <div className="flex flex-col md:flex-row justify-between items-center gap-8 opacity-60">
              <span className="font-black text-amber-950">© 2024 {t.companyName}</span>
              <div className="flex gap-4">
                 <a href={INSTAGRAM_URL} target="_blank" className="font-black uppercase tracking-widest text-xs hover:text-amber-500">Instagram</a>
                 <a href={`https://wa.me/${WHATSAPP_NUMBER}`} target="_blank" className="font-black uppercase tracking-widest text-xs hover:text-amber-500">WhatsApp</a>
              </div>
           </div>
        </footer>
      </div>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(100%); } 100% { transform: translateX(-100%); } }
        .animate-marquee { animation: marquee 30s linear infinite; }
        [dir="rtl"] .animate-marquee { animation: marquee-rtl 30s linear infinite; }
        @keyframes marquee-rtl { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
        .no-scrollbar::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

// --- Sub-Components ---

const NavBtn = ({ label, onClick, highlight }: any) => (
  <button 
    onClick={onClick} 
    className={`px-3 py-2 rounded-xl text-xs font-black transition-all shrink-0 ${highlight ? 'bg-amber-500 text-white' : 'text-amber-950/70 hover:bg-amber-50'}`}
  >
    {label}
  </button>
);

const ProductCard = ({ product, lang, currency, onAdd, t }: any) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const cur = product.prices[sizeIdx];
  return (
    <div className="bg-white rounded-[2.5rem] shadow-lg overflow-hidden flex flex-col border border-amber-50 group hover:shadow-2xl transition-all">
      <div className="h-[320px] bg-white flex items-center justify-center p-8 overflow-hidden">
        <img src={product.image} alt={product.titleEn} className="max-w-full max-h-full object-contain group-hover:scale-105 transition-transform duration-500" />
      </div>
      <div className="p-10 flex-grow flex flex-col">
        <h3 className="text-3xl font-bold text-[#6B4226] mb-3 leading-tight">{lang === 'ar' ? product.titleAr : product.titleEn}</h3>
        <p className="text-[#A16207] mb-8 flex-grow text-lg opacity-80">{lang === 'ar' ? product.descriptionAr : product.descriptionEn}</p>
        <div className="mb-8">
          <p className="text-sm font-black text-[#6B4226]/40 uppercase mb-4">{t.chooseSize}</p>
          <div className="flex flex-wrap gap-2">
            {product.prices.map((p: any, i: number) => (
              <button key={p.id} onClick={() => setSizeIdx(i)} className={`px-5 py-2 rounded-full font-bold text-sm transition-all border-2 ${sizeIdx === i ? 'bg-[#6B4226] text-white border-[#6B4226]' : 'border-slate-100 text-slate-400'}`}>{lang === 'ar' ? p.sizeAr : p.sizeEn}</button>
            ))}
          </div>
        </div>
        <div className="text-center pt-8 border-t border-amber-50">
          <div className="text-4xl font-black text-[#D97706] mb-6">{cur.price} {currency}</div>
          <button onClick={() => onAdd(product.id, cur.id)} className="w-full bg-[#FBBF24] hover:bg-[#F59E0B] text-amber-950 font-black py-4 rounded-2xl shadow-md transition-all">🛒 {lang === 'ar' ? 'أضف للسلة' : 'Add to Basket'}</button>
        </div>
      </div>
    </div>
  );
};

const InputGroup = ({ label, placeholder, value, onChange }: any) => (
  <div>
    <label className="text-[10px] font-black text-amber-900/40 uppercase tracking-widest px-2 mb-2 block">{label}</label>
    <input type="text" value={value} onChange={e => onChange(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 font-bold outline-none focus:border-amber-500 transition-colors" placeholder={placeholder} />
  </div>
);

const CartRow = ({ item, lang, onUpdate, onRemove, isOnly, t }: any) => {
  const prod = PRODUCTS.find(p => p.id === item.productId);
  return (
    <div className="bg-white p-4 rounded-2xl flex items-center gap-4 border border-amber-100 shadow-sm">
      <img src={prod?.image} className="w-12 h-12 object-contain rounded-lg" />
      <div className="flex-grow">
        <p className="font-black text-sm">{lang === 'ar' ? prod?.titleAr : prod?.titleEn}</p>
        <select value={item.priceId} onChange={e => onUpdate(item.id, 'priceId', e.target.value)} className="text-[10px] bg-amber-50 p-1 rounded font-bold">
           {prod?.prices.map(pr => <option key={pr.id} value={pr.id}>{lang === 'ar' ? pr.sizeAr : pr.sizeEn} ({pr.price} {t.currency})</option>)}
        </select>
      </div>
      <div className="flex items-center gap-3">
         <button onClick={() => onUpdate(item.id, 'quantity', Math.max(1, item.quantity - 1))} className="w-8 h-8 rounded-lg bg-slate-100 font-black">-</button>
         <span className="font-black">{item.quantity}</span>
         <button onClick={() => onUpdate(item.id, 'quantity', item.quantity + 1)} className="w-8 h-8 rounded-lg bg-slate-100 font-black">+</button>
      </div>
      {!isOnly && <button onClick={onRemove} className="text-red-400 p-2">✕</button>}
    </div>
  );
};

export default App;

