import { PRODUCTS, TRANSLATIONS, WHATSAPP_NUMBER, INSTAGRAM_URL, FAQS, MOCK_REVIEWS } from './constants';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('ar');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [customer, setCustomer] = useState({ name: '', phone: '', location: '' });

  // AI State
  const [aiMessage, setAiMessage] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiThinking, setIsAiThinking] = useState(false);

  // Reviews State
  const [reviews, setReviews] = useState<any[]>([]);
  const [showReviewForm, setShowReviewForm] = useState(false);
  const [newReview, setNewReview] = useState({ name: '', rating: 5, comment: '' });

  // UI Accordions / Visibility
  const [openProducts, setOpenProducts] = useState(true);
  const [openReviews, setOpenReviews] = useState(false);
  const [addedNotify, setAddedNotify] = useState<string | null>(null);

  const t = useMemo(() => TRANSLATIONS[lang], [lang]);

  // Load reviews from local storage + mock data
  useEffect(() => {
    const saved = localStorage.getItem('honey_house_reviews_v5');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Combine saved reviews with default mock reviews
        setReviews([...parsed, ...MOCK_REVIEWS]);
      } catch (e) {
        setReviews(MOCK_REVIEWS);
      }
    } else {
      setReviews(MOCK_REVIEWS);
    }

    // Initial cart item
    setCart([{ id: 'init-1', productId: PRODUCTS[0].id, priceId: PRODUCTS[0].prices[0].id, quantity: 1 }]);
  }, []);

  useEffect(() => {
    document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const toggleLanguage = () => setLang(prev => (prev === 'ar' ? 'en' : 'ar'));

  const addToBasket = (productId: string, priceId: string) => {
    const newItem: CartItem = {
      id: Math.random().toString(36).substr(2, 9),
      productId,
      priceId,
      quantity: 1
    };
    if (cart.length === 1 && cart[0].id === 'init-1') {
      setCart([newItem]);
    } else {
      setCart([...cart, newItem]);
    }
    const prod = PRODUCTS.find(p => p.id === productId);
    setAddedNotify(lang === 'ar' ? `تمت إضافة ${prod?.titleAr} لسلة` : `Added ${prod?.titleEn} to basket`);
    setTimeout(() => setAddedNotify(null), 3000);
  };

  const updateCartItem = (id: string, field: keyof CartItem, value: any) => {
    setCart(cart.map(item => (item.id === id ? { ...item, [field]: value } : item)));
  };

  const removeProductLine = (id: string) => setCart(cart.filter(item => item.id !== id));

  const totalOrderPrice = useMemo(() => {
    return cart.reduce((acc, item) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      return acc + (priceObj ? priceObj.price * item.quantity : 0);
    }, 0);
  }, [cart]);

  const avgRating = useMemo(() => {
    if (!reviews.length) return "0.0";
    return (reviews.reduce((a, r) => a + (r.rating || 0), 0) / reviews.length).toFixed(1);
  }, [reviews]);

  const handleAiConsult = async (customMsg?: string) => {
    const messageToUse = customMsg || aiMessage;
    if (!messageToUse.trim()) return;
    setIsAiThinking(true);
    setAiResponse('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `You are the Professional Honey Expert for 'Honey House'. 
      Context: Premium Egyptian honey. Language: ${lang}. 
      Explain benefits in detail (4-6 sentences). User Question: ${messageToUse}`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      setAiResponse(response.text || '');
    } catch (e) {
      setAiResponse(lang === 'ar' ? 'عذراً، فشل الاتصال بالذكاء الاصطناعي.' : 'AI Connection Failed.');
    } finally {
      setIsAiThinking(false);
    }
  };

  const submitReview = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newReview.name || !newReview.comment) return;

    const reviewObj = {
      ar: { name: newReview.name, comment: newReview.comment },
      en: { name: newReview.name, comment: newReview.comment },
      rating: newReview.rating
    };

    const currentLocal = JSON.parse(localStorage.getItem('honey_house_reviews_v5') || '[]');
    const updatedLocal = [reviewObj, ...currentLocal];
    localStorage.setItem('honey_house_reviews_v5', JSON.stringify(updatedLocal));

    setReviews([reviewObj, ...reviews]);
    setNewReview({ name: '', rating: 5, comment: '' });
    setShowReviewForm(false);
  };

  const handleSendOrder = () => {
    if (!customer.name || !customer.phone || !customer.location || cart.length === 0) {
      alert(t.errorFields);
      return;
    }
    let summary = '';
    cart.forEach((item, index) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      if (product && priceObj) {
        summary += `${index + 1}. ${lang === 'ar' ? product.titleAr : product.titleEn} (${lang === 'ar' ? priceObj.sizeAr : priceObj.sizeEn}) x ${item.quantity}\n`;
      }
    });
    const msg = `${t.whatsappOrderHeader}\n\n${t.whatsappName} ${customer.name}\n${t.whatsappPhone} ${customer.phone}\n${t.whatsappLocation} ${customer.location}\n\n${summary}\n${t.whatsappTotal} ${totalOrderPrice} ${t.currency}`;
    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  const scrollToSection = (id: string) => document.getElementById(id)?.scrollIntoView({ behavior: 'smooth', block: 'start' });

  return (
    <div className="min-h-screen text-slate-900 bg-[#FEFBF6] selection:bg-amber-200 antialiased font-primary pb-20">

      {/* Toast */}
      {addedNotify && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-amber-600 text-white px-8 py-4 rounded-full font-black shadow-2xl animate-in fade-in slide-in-from-top-4 duration-300">
          🍯 {addedNotify}
        </div>
      )}

      {/* Promo Banner */}
      <div className="bg-gradient-to-r from-amber-600 to-amber-500 text-white text-center py-2.5 font-black text-sm relative z-[60] shadow-sm">
        🚚 {lang === 'ar' ? 'توصيل خلال' : 'Delivery in'} <b>24h – 48h</b> | {lang === 'ar' ? 'توصيل مجاني فوق 200 درهم' : 'Free delivery over 200 AED'}
      </div>

      {/* Professional Header */}
      <header className="sticky top-0 z-50 bg-white/95 backdrop-blur-md border-b border-amber-100 shadow-sm px-4">
        <div className="max-w-7xl mx-auto flex items-center justify-between py-3 overflow-x-auto no-scrollbar gap-6">
          <div className="flex items-center gap-3 shrink-0 cursor-pointer" onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})}>
            <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center p-1 shadow-md">
               <img src="https://imgur.com/doKxqHM.jpeg" alt="Logo" className="w-full h-full object-cover rounded-lg" />
            </div>
            <h1 className="text-xl font-black text-amber-950">{t.companyName}</h1>
          </div>

          <nav className="flex items-center gap-2">
            <NavBtn label={t.navAi} onClick={() => scrollToSection('ai-assistant')} icon="✨" />
            <NavBtn label={t.navSelections} onClick={() => setOpenProducts(!openProducts)} icon="🍯" />
            <NavBtn label={t.navReviews} onClick={() => setOpenReviews(!openReviews)} icon="⭐" />
            <NavBtn label={t.navOrder} onClick={() => scrollToSection('order-form')} highlight icon="📦" />
            <button onClick={toggleLanguage} className="bg-amber-50 text-amber-950 py-2 px-4 rounded-xl text-xs font-black border border-amber-100 hover:bg-amber-100 transition-all uppercase ml-2">
              {lang === 'ar' ? 'EN' : 'AR'}
            </button>
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-12 space-y-16">
        {/* Hero */}
        <section className="text-center">
          <h2 className="text-5xl md:text-8xl font-black text-amber-950 mb-6 tracking-tighter leading-none">{t.companyName}</h2>
          <p className="text-xl md:text-2xl text-amber-800/70 font-medium italic mb-10 max-w-2xl mx-auto">"{t.slogan}"</p>
          <div className="bg-amber-100/50 border-r-4 border-amber-500 text-amber-800 p-8 rounded-2xl shadow-sm inline-block max-w-2xl">
              <h3 className="text-2xl font-black mb-1">{t.grandOpening}</h3>
              <p className="text-lg font-bold opacity-80">{t.limitedTime}</p>
          </div>
        </section>

        {/* AI Expert Section */}
        <section id="ai-assistant" className="scroll-mt-32">
          <div className="bg-amber-900 text-white p-8 md:p-14 rounded-[3rem] shadow-2xl relative overflow-hidden">
            <div className="relative z-10">
              <h2 className="text-3xl font-black mb-4 flex items-center gap-3">
                <span className="text-4xl">✨</span> {t.aiAssistantTitle}
              </h2>
              <p className="opacity-70 text-lg mb-8 max-w-xl">{t.aiAssistantDesc}</p>
              <div className="flex flex-col sm:flex-row gap-4 bg-white/10 p-3 rounded-2xl border border-white/10 backdrop-blur-md">
                 <input 
                  value={aiMessage} onChange={e => setAiMessage(e.target.value)}
                  placeholder={t.aiPlaceholder} className="flex-grow bg-transparent px-5 py-4 outline-none text-white text-lg placeholder:text-white/30"
                  onKeyPress={(e) => e.key === 'Enter' && handleAiConsult()}
                 />
                 <button onClick={() => handleAiConsult()} disabled={isAiThinking} className="bg-amber-500 text-amber-950 px-10 py-4 rounded-xl font-black hover:bg-white transition-all disabled:opacity-50 text-lg">
                   {isAiThinking ? t.aiThinking : (lang === 'ar' ? 'اسأل الخبير' : 'Ask AI')}
                 </button>
              </div>
              {aiResponse && <div className="mt-6 p-6 bg-white/5 rounded-2xl italic leading-relaxed text-xl animate-in fade-in duration-500">"{aiResponse}"</div>}
            </div>
            <div className="absolute -bottom-20 -right-20 w-80 h-80 bg-amber-500/10 rounded-full blur-3xl"></div>
          </div>
        </section>

        {/* Products Accordion */}
        <section id="products-grid" className="scroll-mt-32">
          <button 
            onClick={() => setOpenProducts(!openProducts)} 
            className="w-full flex justify-between items-center text-3xl font-black text-amber-950 mb-8 border-b-2 border-amber-100 pb-4 group"
          >
            <span className="flex items-center gap-3">🍯 {t.navSelections}</span>
            <span className={`transition-transform duration-300 text-amber-400 ${openProducts ? 'rotate-180' : ''}`}>▼</span>
          </button>

          {openProducts && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 animate-in fade-in slide-in-from-top-4 duration-500">
              {PRODUCTS.map(p => (
                <div key={p.id} className="bg-white rounded-[2.5rem] shadow-lg overflow-hidden flex flex-col border border-amber-50 group hover:shadow-2xl transition-all duration-500">
                  <div className="h-[300px] flex items-center justify-center p-8 bg-white"><img src={p.image} className="max-w-full max-h-full object-contain group-hover:scale-105 transition-transform" /></div>
                  <div className="p-10 flex-grow flex flex-col">
                    <h4 className="text-3xl font-black text-[#6B4226] mb-3">{lang === 'ar' ? p.titleAr : p.titleEn}</h4>
                    <p className="text-[#A16207]/70 mb-8 flex-grow text-lg">{lang === 'ar' ? p.descriptionAr : p.descriptionEn}</p>
                    <div className="pt-8 border-t border-amber-50 flex flex-col items-center">
                      <div className="flex flex-wrap gap-2 mb-8">
                         {p.prices.map(pr => (
                           <button key={pr.id} onClick={() => addToBasket(p.id, pr.id)} className="px-6 py-3 rounded-2xl bg-amber-50 text-amber-900 font-black hover:bg-amber-500 hover:text-white transition-all text-sm shadow-sm border border-amber-100">
                             {lang === 'ar' ? pr.sizeAr : pr.sizeEn} — {pr.price} {t.currency}
                           </button>
                         ))}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>

        {/* Reviews Accordion */}
        <section id="reviews-section" className="scroll-mt-32">
          <button 
            onClick={() => setOpenReviews(!openReviews)} 
            className="w-full flex justify-between items-center text-3xl font-black text-amber-950 mb-4 border-b-2 border-amber-100 pb-4 group"
          >
            <span className="flex items-center gap-3">⭐ {t.reviewsTitle} ({reviews.length}) — متوسط {avgRating}</span>
            <span className={`transition-transform duration-300 text-amber-400 ${openReviews ? 'rotate-180' : ''}`}>▼</span>
          </button>

          {openReviews && (
            <div className="space-y-8 animate-in fade-in slide-in-from-top-4 duration-500">
              <div className="flex justify-center">
                <button onClick={() => setShowReviewForm(!showReviewForm)} className="bg-amber-950 text-white px-10 py-4 rounded-2xl font-black hover:bg-amber-800 transition-colors shadow-lg">
                  {t.leaveReview} ✨
                </button>
              </div>

              {showReviewForm && (
                <div className="max-w-xl mx-auto bg-white p-10 rounded-[3rem] shadow-2xl border-2 border-amber-100 animate-in zoom-in-95 duration-300">
                   <form onSubmit={submitReview} className="space-y-6">
                      <input required placeholder={t.namePlaceholder} value={newReview.name} onChange={e => setNewReview({...newReview, name: e.target.value})} className="w-full p-4 bg-slate-50 border rounded-2xl font-bold focus:border-amber-500 outline-none" />
                      <div className="flex gap-2 justify-center">
                        {[1,2,3,4,5].map(s => <button key={s} type="button" onClick={() => setNewReview({...newReview, rating: s})} className={`text-3xl ${newReview.rating >= s ? 'text-amber-400' : 'text-slate-200'}`}>★</button>)}
                      </div>
                      <textarea required placeholder={lang === 'ar' ? 'اكتب تجربتك...' : 'Write your review...'} value={newReview.comment} onChange={e => setNewReview({...newReview, comment: e.target.value})} className="w-full p-4 bg-slate-50 border rounded-2xl font-bold min-h-[120px] outline-none" />
                      <button className="w-full bg-green-500 text-white py-4 rounded-2xl font-black text-lg">نشر التقييم</button>
                   </form>
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {reviews.map((r, i) => (
                  <div key={i} className="bg-white p-8 rounded-3xl border border-amber-50 shadow-sm hover:shadow-md transition-shadow">
                    <div className="flex text-amber-400 mb-4">{"★".repeat(r.rating)}</div>
                    <p className="text-amber-950/80 italic text-lg mb-6 leading-relaxed">"{lang === 'ar' ? r.ar.comment : r.en.comment}"</p>
                    <p className="font-black text-amber-950">{lang === 'ar' ? r.ar.name : r.en.name}</p>
                  </div>
                ))}
              </div>
            </div>
          )}
        </section>

        {/* Order Form */}
        <section id="order-form" className="bg-white p-10 md:p-16 rounded-[4rem] shadow-2xl border border-amber-100/50 max-w-4xl mx-auto scroll-mt-32">
          <h2 className="text-4xl font-black text-amber-950 mb-10 text-center">{t.orderNow}</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
            <InputGroup label={t.nameLabel} placeholder={t.namePlaceholder} value={customer.name} onChange={v => setCustomer({...customer, name: v})} />
            <InputGroup label={t.phoneLabel} placeholder={t.phonePlaceholder} value={customer.phone} onChange={v => setCustomer({...customer, phone: v})} />
          </div>
          <InputGroup label={t.locationLabel} placeholder={t.locationPlaceholder} value={customer.location} onChange={v => setCustomer({...customer, location: v})} />

          <div className="mt-12 bg-slate-50 p-6 rounded-3xl space-y-4">
             <h4 className="font-black text-amber-900 text-xs uppercase tracking-widest">{lang === 'ar' ? 'ملخص الطلب' : 'Order Summary'}</h4>
             {cart.map(item => (
               <div key={item.id} className="flex items-center gap-4 bg-white p-4 rounded-2xl shadow-sm border border-amber-100/30">
                 <div className="flex-grow">
                   <p className="font-black text-sm">{lang === 'ar' ? PRODUCTS.find(p => p.id === item.productId)?.titleAr : PRODUCTS.find(p => p.id === item.productId)?.titleEn}</p>
                   <select value={item.priceId} onChange={e => updateCartItem(item.id, 'priceId', e.target.value)} className="text-[10px] bg-amber-50 p-1 rounded font-bold border-none outline-none">
                     {PRODUCTS.find(p => p.id === item.productId)?.prices.map(pr => <option key={pr.id} value={pr.id}>{lang === 'ar' ? pr.sizeAr : pr.sizeEn}</option>)}
                   </select>
                 </div>
                 <div className="flex items-center gap-2">
                   <button onClick={() => updateCartItem(item.id, 'quantity', Math.max(1, item.quantity - 1))} className="w-8 h-8 rounded-lg bg-slate-100 font-black">-</button>
                   <span className="font-black text-sm">{item.quantity}</span>
                   <button onClick={() => updateCartItem(item.id, 'quantity', item.quantity + 1)} className="w-8 h-8 rounded-lg bg-slate-100 font-black">+</button>
                   {cart.length > 1 && <button onClick={() => removeProductLine(item.id)} className="text-red-400 ml-2">✕</button>}
                 </div>
               </div>
             ))}
             <button onClick={() => scrollToSection('products-grid')} className="w-full py-3 rounded-xl border-2 border-dashed border-amber-200 text-amber-800 font-bold hover:bg-amber-100">+ {t.addProduct}</button>
          </div>

          <div className="mt-10 flex flex-col items-center">
            <div className="text-5xl font-black text-amber-600 mb-8">{totalOrderPrice} {t.currency}</div>
            <button onClick={handleSendOrder} className="w-full bg-amber-500 text-white font-black py-6 rounded-2xl text-xl shadow-xl hover:bg-amber-600 transition-all flex items-center justify-center gap-3">
              <span>📲</span> {t.sendOrder}
            </button>
          </div>
        </section>
      </main>

      <footer className="mt-24 text-center opacity-40 py-10 border-t border-amber-100">
         <p className="font-black text-amber-950">© 2024 {t.companyName} | Handcrafted Honey Excellence</p>
      </footer>
    </div>
  );
};

// --- Sub Components ---

const NavBtn = ({ label, onClick, highlight, icon }: any) => (
  <button onClick={onClick} className={`flex items-center gap-2 px-4 py-3 rounded-2xl text-xs font-black transition-all shrink-0 ${highlight ? 'bg-amber-500 text-white shadow-lg' : 'text-amber-950/70 hover:bg-amber-50'}`}>
    <span className="text-lg">{icon}</span>
    <span className="whitespace-nowrap uppercase tracking-tighter">{label}</span>
  </button>
);

const InputGroup = ({ label, placeholder, value, onChange }: any) => (
  <div className="space-y-2">
    <label className="text-[10px] font-black text-amber-900/30 uppercase tracking-widest px-2">{label}</label>
    <input type="text" value={value} onChange={e => onChange(e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl font-bold focus:border-amber-500 outline-none transition-colors" placeholder={placeholder} />
  </div>
);

export default App;
